const body   = $input.first().json?.body || {};
const userId = body.userId || null;
if (!userId) throw new Error('userId mancante');

const update = { userId, updatedAt: new Date().toISOString() };

// macroTopics = topic selezionati dall'utente (hard filter)
if (body.macroTopics)         update.macroTopics         = body.macroTopics;
if (body.keywords)            update.keywords            = body.keywords;
if (body.weights)             update.weights             = body.weights;
if (body.sentimentPreference) update.sentimentPreference = body.sentimentPreference;
if (body.preferredSources)    update.preferredSources    = body.preferredSources;

return [{ json: update }];

const body   = $input.first().json?.body || {};
const userId = body.userId || body.user_id || null;
const limit  = parseInt(body.limit || '20', 10);

if (!userId) throw new Error('userId mancante nella richiesta');

return [{ json: { userId, limit } }];

const item   = $input.first().json;
const userId = $('Extract User Params').first().json.userId;
const limit  = $('Extract User Params').first().json.limit;

const MACRO_TOPICS = [
  'Intelligenza Artificiale', 'Cybersecurity', 'Business & Finanza',
  'Politica & Geopolitica', 'Startup & Innovazione', 'Software & Sviluppo',
  'Scienza & Ricerca', 'Energia & Ambiente', 'Economia & Mercati',
  'Social Media & Cultura', 'Salute & Medicina', 'Trasporti & Mobilità'
];

const defaultWeights = Object.fromEntries(MACRO_TOPICS.map(t => [t, 1.0]));

if (!item || !item.userId) {
  console.warn(`[BriefAI W3] Profilo non trovato per userId=${userId}. Uso default.`);
  return [{ json: {
    userId, limit,
    profile: {
      macroTopics:         MACRO_TOPICS,   // default = tutti i topic
      keywords:            [],
      weights:             defaultWeights,
      sentimentPreference: 'all',
      preferredSources:    []
    }
  }}];
}

return [{ json: {
  userId, limit,
  profile: {
    macroTopics:         item.macroTopics         || MACRO_TOPICS,
    keywords:            item.keywords            || [],
    weights:             item.weights             || defaultWeights,
    sentimentPreference: item.sentimentPreference || 'all',
    preferredSources:    item.preferredSources    || []
  }
}}];

// ============================================================
// RANKING ENGINE — BriefAI Workflow 3
// score = weighted_interest(55%) + keyword_match(25%) + recency(15%) + source_bonus
// HARD FILTER: vengono mostrati SOLO gli articoli appartenenti
//              ai macroTopics selezionati dall'utente.
// ============================================================

const profileData = $('Normalize Profile').first().json;
const { profile, limit } = profileData;
const articles = $input.all().map(i => i.json);

const now           = Date.now();
const MAX_AGE_HOURS = 168;

// ------------------------------------------------------------------
// HARD FILTER PER MACRO-TOPIC
// Mostra solo articoli che matchano almeno uno dei topic selezionati.
// Se l'utente non ha selezionato nulla (caso anomalo) mostra tutto.
// ------------------------------------------------------------------
const selectedTopics = profile.macroTopics || [];

const filtered = selectedTopics.length === 0
  ? articles
  : articles.filter(a =>
      (a.macroTopics || []).some(t => selectedTopics.includes(t))
    );

console.log(`[BriefAI W3] Articoli totali: ${articles.length} | Dopo hard filter topic: ${filtered.length} | Topic selezionati: ${selectedTopics.join(', ')}`);

// ------------------------------------------------------------------
// FUNZIONI DI SCORING
// ------------------------------------------------------------------
function recencyScore(pubDateStr) {
  if (!pubDateStr) return 0;
  const pub = new Date(pubDateStr).getTime();
  if (isNaN(pub)) return 0;
  const ageHours = (now - pub) / 3600000;
  if (ageHours <= 0)             return 1.0;
  if (ageHours >= MAX_AGE_HOURS) return 0.0;
  return 1 - (ageHours / MAX_AGE_HOURS);
}

function keywordScore(article, keywords) {
  if (!keywords || keywords.length === 0) return 0.5;
  const haystack = [
    article.title   || '',
    article.summary || '',
    article.content || ''
  ].join(' ').toLowerCase();
  let matches = 0;
  for (const kw of keywords) {
    if (haystack.includes(kw.toLowerCase())) matches++;
  }
  return Math.min(matches / keywords.length, 1.0);
}

function interestScore(article, weights, selectedTopics) {
  const articleTopics = (article.macroTopics || []).filter(t => selectedTopics.includes(t));
  if (articleTopics.length === 0) return 0.5;
  const scores = articleTopics.map(t => weights[t] !== undefined ? Math.min(weights[t] / 1.5, 1.0) : 0.5);
  return Math.max(...scores);
}

function sentimentBonus(article, preference) {
  if (preference === 'all') return 0.1;
  return article.sentiment === preference ? 0.2 : 0.0;
}

function sourceBonus(article, preferredSources) {
  if (!preferredSources || preferredSources.length === 0) return 0;
  return preferredSources.includes(article.source) ? 0.1 : 0.0;
}

// ------------------------------------------------------------------
// SCORING LOOP
// ------------------------------------------------------------------
const scored = [];

for (const article of filtered) {
  const rScore   = recencyScore(article.pubDate);
  const kScore   = keywordScore(article, profile.keywords);
  const iScore   = interestScore(article, profile.weights, selectedTopics);
  const sBonus   = sentimentBonus(article, profile.sentimentPreference);
  const srcBonus = sourceBonus(article, profile.preferredSources);

  const totalScore =
    (iScore * 0.55) +
    (kScore * 0.25) +
    (rScore * 0.15) +
    sBonus          +
    srcBonus;

  scored.push({
    data: article,
    _score: parseFloat(totalScore.toFixed(4)),
    _scoreBreakdown: {
      weighted_interest: parseFloat((iScore * 0.55).toFixed(4)),
      keyword_match:     parseFloat((kScore * 0.25).toFixed(4)),
      recency:           parseFloat((rScore * 0.15).toFixed(4)),
      sentiment_bonus:   parseFloat(sBonus.toFixed(4)),
      source_bonus:      parseFloat(srcBonus.toFixed(4))
    }
  });
}

scored.sort((a, b) => b._score - a._score);
const feed = scored.slice(0, limit);

// ------------------------------------------------------------------
// RESPONSE
// ------------------------------------------------------------------
const response = {
  userId:        profileData.userId,
  generatedAt:   new Date().toISOString(),
  totalFetched:  articles.length,
  totalFiltered: filtered.length,
  totalReturned: feed.length,
  profile: {
    macroTopics:         selectedTopics,
    sentimentPreference: profile.sentimentPreference
  },
  articles: feed.map(a => ({
    id:             a.data.uniqueKey,
    title:          a.data.title,
    url:            a.data.url,
    source:         a.data.source,
    macroTopics:    a.data.macroTopics || [],
    pubDate:        a.data.pubDate,
    summary:        a.data.summary,
    sentiment:      a.data.sentiment,
    entities:       a.data.entities    || [],
    score:          a._score,
    scoreBreakdown: a._scoreBreakdown
  }))
};

return [{ json: response }];

// FIX BUG 7: prepara esplicitamente il campo lastFeedGeneratedAt
const rankingOutput = $input.first().json;
return [{ json: {
  userId:                rankingOutput.userId,
  lastFeedGeneratedAt:   rankingOutput.generatedAt
}}];
